-- Luxury Real Estate Developers
-- Auto-generated from developer_outreach_CORRECTED.csv

CREATE TABLE IF NOT EXISTS developers (
  id SERIAL PRIMARY KEY,
  developer_seller TEXT,
  state CHAR(2),
  city TEXT,
  deals_in_market INTEGER,
  total_deals_nationwide INTEGER,
  total_volume_market BIGINT,
  avg_sale_price_market BIGINT,
  is_corp_llc BOOLEAN,
  sample_addresses TEXT,
  created_at TIMESTAMP DEFAULT NOW()
);


-- Indexes for common queries
CREATE INDEX idx_developers_state ON developers(state);
CREATE INDEX idx_developers_city ON developers(city);
CREATE INDEX idx_developers_deals ON developers(deals_in_market DESC);
CREATE INDEX idx_developers_volume ON developers(total_volume_market DESC);
